sql:
SELECT AVG(gold_drop) AS avg_gold_drop
FROM enemies
WHERE enemy_type = 'normal' AND experience_points > 100;

SELECT SUM(gold_drop) AS Total_Gold_Drop
FROM enemies
WHERE enemy_type = 'Boss';

SELECT player_id, COUNT(*) AS Defeated_Enemies
FROM player_enemies
GROUP BY player_id;

SELECT AVG(e.health_points) AS average_health_points
FROM enemies e
WHERE e.enemy_id IN (
    SELECT pe.enemy_id
    FROM player_enemies pe
);

SELECT weapon_id
FROM weapons
WHERE level_requirement > 5;

SELECT DISTINCT players.player_name
FROM players
JOIN boss_battles ON players.player_id = boss_battles.player_id;

SELECT bosses.boss_name, bosses.description, boss_battles.outcome
FROM bosses
JOIN boss_battles ON bosses.boss_id = boss_battles.boss_id;

SELECT DISTINCT i.*
FROM items i
JOIN enemy_drops ed ON i.item_id = ed.item_id;

external_knowledge:
- 'particularly high weaknesses' refers to damage multipliers greater than the average;
- 'intensity of their weakness' corresponds to the value of the damage multipliers;
- 'top ten' indicates limiting the results to the first ten entries.
